import { useState } from "react";
import "./index.css";
import ConnectionScreen from "./components/ConnectionScreen";
import InputForm from "./components/InputForm";
import DashboardScreen from "./components/DashboardScreen";
import { generateDashboard } from "./api";

export default function App() {
  const [screen, setScreen] = useState("connect");
  const [connectionData, setConnectionData] = useState(null);
  const [dashboardData, setDashboardData] = useState(null);
  const [colorSchema, setColorSchema] = useState("default");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleConnected = (data) => { setConnectionData(data); setScreen("input"); };

  const handleGenerate = async (formData) => {
    setLoading(true); setError("");
    setColorSchema(formData.color_schema);
    try {
      const result = await generateDashboard(formData);
      setDashboardData(result); setScreen("dashboard");
    } catch (e) {
      setError(e.response?.data?.detail || "Dashboard generation failed. Please try again.");
    } finally { setLoading(false); }
  };

  const handleReset = () => { setDashboardData(null); setScreen("input"); setError(""); };

  return (
    <>
      <div style={bgGrid} />
      {error && (
        <div style={errorToast}>
          <span>⚠️ {error}</span>
          <button onClick={() => setError("")} style={closeBtn}>✕</button>
        </div>
      )}
      {screen === "connect" && <ConnectionScreen onConnected={handleConnected} />}
      {screen === "input" && connectionData && <InputForm connectionData={connectionData} onSubmit={handleGenerate} loading={loading} />}
      {screen === "dashboard" && dashboardData && <DashboardScreen data={dashboardData} sessionId={connectionData?.session_id} colorSchema={colorSchema} onReset={handleReset} />}
    </>
  );
}

const bgGrid = { position: "fixed", inset: 0, backgroundImage: `linear-gradient(rgba(79,142,247,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(79,142,247,0.03) 1px, transparent 1px)`, backgroundSize: "48px 48px", pointerEvents: "none", zIndex: 0 };
const errorToast = { position: "fixed", top: "20px", left: "50%", transform: "translateX(-50%)", zIndex: 1000, display: "flex", alignItems: "center", gap: "12px", padding: "12px 20px", background: "rgba(247,89,89,0.15)", border: "1px solid rgba(247,89,89,0.4)", borderRadius: "12px", color: "#f79999", fontSize: "14px", backdropFilter: "blur(12px)", maxWidth: "90vw" };
const closeBtn = { background: "none", border: "none", color: "#f79999", cursor: "pointer", fontSize: "16px", padding: "0 4px" };
